SELECT c.*, p.project_name FROM elder_consulting c LEFT JOIN elder_project p ON c.project_id = p.id WHERE c.del_flag = 0
AND c.project_id IN (
#{id}
)
AND c.project_id = #{elderConsulting.projectId}
AND c.`name` LIKE concat(concat('%',#{elderConsulting.name}),'%')
AND c.consult_type_code = #{elderConsulting.consultTypeCode}
AND c.follow_status = #{elderConsulting.followStatus}
AND c.phone LIKE concat(concat('%',#{elderConsulting.phone}),'%')
AND c.receptionist_name LIKE concat(concat('%',#{elderConsulting.receptionistName}),'%')
order by c.create_time desc

